    // ==================== Melting Point and Boiling Point Determination ====================

    { q: "The melting point of a pure organic compound is:", options: ["Sharp and characteristic", "Broad range", "Always 100°C", "Always below 50°C"], ans: "Sharp and characteristic", topic: "Melting Point and Boiling Point Determination" },

    { q: "A mixed melting point is used to:", options: ["Confirm identity of compound", "Determine boiling point", "Measure purity only", "Determine molecular weight"], ans: "Confirm identity of compound", topic: "Melting Point and Boiling Point Determination" },

    { q: "If the melting point of a sample is lower and broader than the pure compound, it indicates:", options: ["High purity", "Presence of impurity", "The compound is wet", "Both presence of impurity and wet sample"], ans: "Presence of impurity", topic: "Melting Point and Boiling Point Determination" },

    { q: "The boiling point determination is usually done by:", options: ["Distillation method", "Melting point apparatus", "Titration", "Flame test"], ans: "Distillation method", topic: "Melting Point and Boiling Point Determination" },

    { q: "The capillary tube method is commonly used for:", options: ["Boiling point", "Melting point", "Density", "Solubility"], ans: "Melting point", topic: "Melting Point and Boiling Point Determination" },

    { q: "The rate of heating near the melting point should be:", options: ["Very fast", "Slow (1-2°C per minute)", "No heating", "Constant high temperature"], ans: "Slow (1-2°C per minute)", topic: "Melting Point and Boiling Point Determination" },

    { q: "A sharp melting point indicates:", options: ["Impure compound", "Pure compound", "Wet sample", "Decomposition"], ans: "Pure compound", topic: "Melting Point and Boiling Point Determination" },

    { q: "The melting point apparatus commonly used is:", options: ["Thiele tube", "Gallenkamp apparatus", "Both", "None"], ans: "Both", topic: "Melting Point and Boiling Point Determination" },

    { q: "Boiling point is affected by:", options: ["Pressure", "Purity", "Both pressure and purity", "Only temperature"], ans: "Both pressure and purity", topic: "Melting Point and Boiling Point Determination" },

    { q: "The correction for boiling point at different pressures is done using:", options: ["Nomograph", "Calculator", "Titration", "Flame test"], ans: "Nomograph", topic: "Melting Point and Boiling Point Determination" },

    { q: "Impure samples usually show:", options: ["Sharp melting point", "Broad melting range", "Higher melting point", "No change"], ans: "Broad melting range", topic: "Melting Point and Boiling Point Determination" },

    { q: "The melting point of a compound is used to:", options: ["Determine molecular weight", "Check purity and identity", "Measure solubility", "Determine boiling point"], ans: "Check purity and identity", topic: "Melting Point and Boiling Point Determination" },

    { q: "In the capillary tube method, the sample is heated until:", options: ["It melts completely", "It starts melting", "It decomposes", "It boils"], ans: "It melts completely", topic: "Melting Point and Boiling Point Determination" },

    { q: "The thermometer in melting point apparatus should be calibrated because:", options: ["It may give wrong reading", "It is expensive", "It is colored", "It is small"], ans: "It may give wrong reading", topic: "Melting Point and Boiling Point Determination" },

    { q: "The boiling point is defined as the temperature at which:", options: ["Vapor pressure equals atmospheric pressure", "Solid melts", "Liquid freezes", "Gas condenses"], ans: "Vapor pressure equals atmospheric pressure", topic: "Melting Point and Boiling Point Determination" },

    { q: "A depressed melting point indicates:", options: ["Pure compound", "Impurity present", "High molecular weight", "Low density"], ans: "Impurity present", topic: "Melting Point and Boiling Point Determination" },

    { q: "The Thiele tube method is used for:", options: ["Boiling point determination", "Melting point determination", "Titration", "Distillation"], ans: "Melting point determination", topic: "Melting Point and Boiling Point Determination" },

    { q: "The sample in capillary tube should be:", options: ["Packed tightly", "Loosely packed", "Wet", "Large amount"], ans: "Packed tightly", topic: "Melting Point and Boiling Point Determination" },

    { q: "The melting point range of a pure compound is usually:", options: ["More than 5°C", "Less than 1°C", "Exactly 0°C", "More than 10°C"], ans: "Less than 1°C", topic: "Melting Point and Boiling Point Determination" },

    { q: "Boiling point determination by Siwoloboff method is used for:", options: ["Large volume samples", "Small volume samples", "Solids", "Gases"], ans: "Small volume samples", topic: "Melting Point and Boiling Point Determination" }, 


    // ==================== Chromatography Techniques ====================

    { q: "Chromatography is a technique used for:", options: ["Separation of mixtures", "Identification only", "Heating", "Titration"], ans: "Separation of mixtures", topic: "Chromatography Techniques" },

    { q: "The stationary phase in paper chromatography is:", options: ["Water adsorbed on paper", "Solvent", "Silica gel", "Alumina"], ans: "Water adsorbed on paper", topic: "Chromatography Techniques" },

    { q: "In thin layer chromatography (TLC), the stationary phase is usually:", options: ["Paper", "Silica gel or alumina", "Water", "Solvent"], ans: "Silica gel or alumina", topic: "Chromatography Techniques" },

    { q: "The Rf value is calculated as:", options: ["Distance travelled by solvent / Distance travelled by solute", "Distance travelled by solute / Distance travelled by solvent", "Distance travelled by solute only", "Distance travelled by solvent only"], ans: "Distance travelled by solute / Distance travelled by solvent", topic: "Chromatography Techniques" },

    { q: "A higher Rf value means the compound is:", options: ["More polar", "Less polar", "Heavier", "Lighter"], ans: "Less polar", topic: "Chromatography Techniques" },

    { q: "The mobile phase in chromatography is:", options: ["The stationary phase", "The solvent or gas that moves", "The paper", "The sample"], ans: "The solvent or gas that moves", topic: "Chromatography Techniques" },

    { q: "Column chromatography is mainly used for:", options: ["Qualitative analysis", "Separation and purification of compounds", "Melting point determination", "Titration"], ans: "Separation and purification of compounds", topic: "Chromatography Techniques" },

    { q: "The principle of chromatography is based on:", options: ["Difference in boiling points", "Difference in solubility and adsorption", "Difference in density", "Difference in color"], ans: "Difference in solubility and adsorption", topic: "Chromatography Techniques" },

    { q: "In paper chromatography, the solvent front is:", options: ["The starting line", "The farthest point reached by the solvent", "The sample spot", "The origin"], ans: "The farthest point reached by the solvent", topic: "Chromatography Techniques" },

    { q: "Visualization of spots in TLC can be done by:", options: ["UV light", "Iodine vapor", "Spraying reagents", "All of the above"], ans: "All of the above", topic: "Chromatography Techniques" },

    { q: "Gas chromatography is best for:", options: ["Non-volatile compounds", "Volatile and thermally stable compounds", "Ionic compounds", "High molecular weight polymers"], ans: "Volatile and thermally stable compounds", topic: "Chromatography Techniques" },

    { q: "The stationary phase in gas chromatography is usually:", options: ["Paper", "Liquid coated on solid support", "Silica gel", "Water"], ans: "Liquid coated on solid support", topic: "Chromatography Techniques" },

    { q: "The Rf value is always:", options: ["Greater than 1", "Less than or equal to 1", "Equal to 1", "Negative"], ans: "Less than or equal to 1", topic: "Chromatography Techniques" },

    { q: "The main advantage of TLC over paper chromatography is:", options: ["Faster separation", "Better resolution", "Both faster and better resolution", "Cheaper"], ans: "Both faster and better resolution", topic: "Chromatography Techniques" },

    { q: "In column chromatography, the eluent is:", options: ["The stationary phase", "The mobile phase", "The sample", "The column"], ans: "The mobile phase", topic: "Chromatography Techniques" },

    { q: "The order of elution in normal phase chromatography is:", options: ["Non-polar first", "Polar first", "All at once", "Random"], ans: "Non-polar first", topic: "Chromatography Techniques" },

    { q: "The purpose of spotting the sample in TLC is to:", options: ["Apply a small concentrated spot", "Cover the whole plate", "Dry the plate", "Heat the plate"], ans: "Apply a small concentrated spot", topic: "Chromatography Techniques" },

    { q: "The developing chamber in paper chromatography should be:", options: ["Open", "Saturated with solvent vapor", "Heated", "Cooled"], ans: "Saturated with solvent vapor", topic: "Chromatography Techniques" },

    { q: "Which of the following is a type of chromatography?", options: ["Paper chromatography", "Thin layer chromatography", "Gas chromatography", "All of the above"], ans: "All of the above", topic: "Chromatography Techniques" },

    { q: "The retention time in gas chromatography is used to:", options: ["Identify the compound", "Measure mass", "Determine color", "Calculate Rf value"], ans: "Identify the compound", topic: "Chromatography Techniques" },


    // ==================== Laboratory Safety and First Aid ====================

    { q: "The most important rule in the chemistry laboratory is:", options: ["Wear lab coat", "Follow safety instructions", "Work fast", "Use expensive equipment"], ans: "Follow safety instructions", topic: "Laboratory Safety and First Aid" },

    { q: "Safety goggles are worn to protect the eyes from:", options: ["Heat", "Chemical splashes", "Bad smell", "Noise"], ans: "Chemical splashes", topic: "Laboratory Safety and First Aid" },

    { q: "If acid is spilled on the skin, the first action should be:", options: ["Add base", "Wash with plenty of water", "Ignore it", "Apply oil"], ans: "Wash with plenty of water", topic: "Laboratory Safety and First Aid" },

    { q: "Never pipette by mouth because:", options: ["It is slow", "It can cause accidental ingestion of chemicals", "It is old fashioned", "It is expensive"], ans: "It can cause accidental ingestion of chemicals", topic: "Laboratory Safety and First Aid" },

    { q: "The fire extinguisher for electrical fire is:", options: ["Water", "CO2 or dry powder", "Foam", "Sand"], ans: "CO2 or dry powder", topic: "Laboratory Safety and First Aid" },

    { q: "Long hair in the laboratory should be:", options: ["Left loose", "Tied back", "Cut short", "Dyed"], ans: "Tied back", topic: "Laboratory Safety and First Aid" },

    { q: "Eating and drinking in the laboratory is:", options: ["Allowed", "Strictly prohibited", "Allowed only for water", "Allowed for snacks"], ans: "Strictly prohibited", topic: "Laboratory Safety and First Aid" },

    { q: "The first aid for burns is:", options: ["Apply ice", "Run cold water over the area", "Apply oil", "Cover with cloth"], ans: "Run cold water over the area", topic: "Laboratory Safety and First Aid" },

    { q: "Which of the following is a hazardous chemical?", options: ["Water", "Concentrated acids", "Sugar", "Salt"], ans: "Concentrated acids", topic: "Laboratory Safety and First Aid" },

    { q: "The emergency shower is used when:", options: ["There is a fire", "Large amount of chemical is spilled on the body", "Minor cut", "Eye irritation"], ans: "Large amount of chemical is spilled on the body", topic: "Laboratory Safety and First Aid" },

    { q: "The eyewash station is used for:", options: ["Washing hands", "Flushing chemicals from eyes", "Drinking water", "Cooling solutions"], ans: "Flushing chemicals from eyes", topic: "Laboratory Safety and First Aid" },

    { q: "Never work alone in the laboratory because:", options: ["It is boring", "In case of accident, help is needed", "It is against the rule", "Both B and C"], ans: "In case of accident, help is needed", topic: "Laboratory Safety and First Aid" },

    { q: "The correct way to smell a chemical is:", options: ["Directly", "By wafting the vapor towards the nose", "By putting nose inside the container", "Not smelling at all"], ans: "By wafting the vapor towards the nose", topic: "Laboratory Safety and First Aid" },

    { q: "Broken glassware should be disposed in:", options: ["Normal dustbin", "Sharps container", "Sink", "Any bin"], ans: "Sharps container", topic: "Laboratory Safety and First Aid" },

    { q: "The symbol for corrosive substances is:", options: ["Flame", "Skull and crossbones", "Hand and surface being eaten away", "Exploding bomb"], ans: "Hand and surface being eaten away", topic: "Laboratory Safety and First Aid" },

    { q: "In case of fire on clothing, the best action is:", options: ["Run", "Stop, drop and roll", "Use water", "Ignore"], ans: "Stop, drop and roll", topic: "Laboratory Safety and First Aid" },

    { q: "The laboratory coat should be:", options: ["Short sleeved", "Long sleeved and buttoned", "Removed during experiment", "Made of cotton only"], ans: "Long sleeved and buttoned", topic: "Laboratory Safety and First Aid" },

    { q: "Never heat a closed container because:", options: ["It may explode", "It is slow", "It wastes energy", "It is not necessary"], ans: "It may explode", topic: "Laboratory Safety and First Aid" },

    { q: "The first aid box in the laboratory should contain:", options: ["Only bandages", "Antiseptic, bandages, burn cream, eye wash", "Only medicines", "Nothing"], ans: "Antiseptic, bandages, burn cream, eye wash", topic: "Laboratory Safety and First Aid" },

    { q: "The most dangerous practice in the laboratory is:", options: ["Wearing safety goggles", "Pipetting by mouth", "Washing hands after experiment", "Reading instructions"], ans: "Pipetting by mouth", topic: "Laboratory Safety and First Aid" }

