    { q: "The laboratory coat should be:", options: ["Short sleeved", "Long sleeved and buttoned up", "Removed during experiment", "Made of cotton only"], ans: "Long sleeved and buttoned up", topic: "Laboratory Safety and First Aid" },

    { q: "Never heat a closed container because it may:", options: ["Cool down", "Explode due to pressure build-up", "Save energy", "Not necessary"], ans: "Explode due to pressure build-up", topic: "Laboratory Safety and First Aid" },

    { q: "The first aid box should contain at least:", options: ["Only bandages", "Antiseptic, bandages, burn cream, eye wash solution", "Only medicines", "Nothing"], ans: "Antiseptic, bandages, burn cream, eye wash solution", topic: "Laboratory Safety and First Aid" },

    { q: "The most dangerous practice in the laboratory is:", options: ["Wearing safety goggles", "Pipetting by mouth", "Washing hands after work", "Reading the procedure"], ans: "Pipetting by mouth", topic: "Laboratory Safety and First Aid" }

