    { q: "The comparison of EMF of two cells is done using:", options: ["Potentiometer", "Meter bridge", "Ohm's law apparatus", "Resonance tube"], ans: "Potentiometer", topic: "Electricity and Magnetism Experiments" },

    { q: "The magnetic field due to a current-carrying solenoid is determined using:", options: ["Tangent galvanometer or search coil", "Simple pendulum", "Hooke's law", "Young's modulus"], ans: "Tangent galvanometer or search coil", topic: "Electricity and Magnetism Experiments" },

    { q: "The verification of Kirchhoff's laws is done using:", options: ["A network of resistances", "Single resistor", "Capacitor only", "Inductor only"], ans: "A network of resistances", topic: "Electricity and Magnetism Experiments" },

    { q: "The figure of merit of a galvanometer is:", options: ["Current per unit deflection", "Voltage per unit deflection", "Resistance", "EMF"], ans: "Current per unit deflection", topic: "Electricity and Magnetism Experiments" },

    { q: "To convert a galvanometer into an ammeter, we connect:", options: ["High resistance in series", "Low resistance (shunt) in parallel", "High resistance in parallel", "No resistance"], ans: "Low resistance (shunt) in parallel", topic: "Electricity and Magnetism Experiments" },

    { q: "To convert a galvanometer into a voltmeter, we connect:", options: ["Low resistance in parallel", "High resistance in series", "Low resistance in series", "No resistance"], ans: "High resistance in series", topic: "Electricity and Magnetism Experiments" },

    { q: "The potentiometer is based on the principle of:", options: ["Null deflection method", "Ohm's law", "Kirchhoff's law", "Faraday's law"], ans: "Null deflection method", topic: "Electricity and Magnetism Experiments" },

    { q: "The magnetic field inside a long solenoid is:", options: ["Zero", "Uniform and strong", "Non-uniform", "Very weak"], ans: "Uniform and strong", topic: "Electricity and Magnetism Experiments" },

    { q: "The direction of magnetic field due to current is given by:", options: ["Right hand thumb rule", "Left hand rule", "Fleming's left hand rule", "Fleming's right hand rule"], ans: "Right hand thumb rule", topic: "Electricity and Magnetism Experiments" },

    { q: "The induced EMF in a coil is given by Faraday's law:", options: ["e = -dφ/dt", "e = IR", "e = V/R", "e = BIL"], ans: "e = -dφ/dt", topic: "Electricity and Magnetism Experiments" },

    { q: "The resonance frequency in LCR circuit is:", options: ["f = 1/(2π√(LC))", "f = 2π√(LC)", "f = LC", "f = 1/(LC)"], ans: "f = 1/(2π√(LC))", topic: "Electricity and Magnetism Experiments" },

    { q: "The capacitance of a parallel plate capacitor is given by:", options: ["C = ε₀ A / d", "C = d / ε₀ A", "C = ε₀ d / A", "C = A d"], ans: "C = ε₀ A / d", topic: "Electricity and Magnetism Experiments" },

    { q: "The time constant of an RC circuit is:", options: ["τ = RC", "τ = R/C", "τ = C/R", "τ = 1/RC"], ans: "τ = RC", topic: "Electricity and Magnetism Experiments" },

    { q: "The self-inductance of a coil opposes:", options: ["Change in current", "Change in voltage", "Change in resistance", "Change in capacitance"], ans: "Change in current", topic: "Electricity and Magnetism Experiments" }

