    { q: "Disease control programmes include:", options: ["Vaccination, deworming, biosecurity and surveillance", "Only culling", "Only isolation", "Only treatment"], ans: "Vaccination, deworming, biosecurity and surveillance", topic: "Disease Control and Prevention" },
    { q: "Farmers should practice:", options: ["All-in-all-out system in poultry and pig farms", "Continuous stocking", "Mixing ages", "Mixing species"], ans: "All-in-all-out system in poultry and pig farms", topic: "Disease Control and Prevention" },
    { q: "Disease control and prevention contribute to:", options: ["Healthy animals, higher productivity and safe food", "Only higher cost", "Only more loss", "Only low yield"], ans: "Healthy animals, higher productivity and safe food", topic: "Disease Control and Prevention" },
    { q: "Students learn disease control to:", options: ["Protect livestock health and ensure sustainable production", "Only do nutrition", "Only breeding", "Only management"], ans: "Protect livestock health and ensure sustainable production", topic: "Disease Control and Prevention" },

    // Pasture and Range Management
    { q: "Pasture is:", options: ["Land covered with grasses and legumes for grazing animals", "Only crop land", "Only forest", "Only bare land"], ans: "Land covered with grasses and legumes for grazing animals", topic: "Pasture and Range Management" },
    { q: "Range management deals with:", options: ["Natural vegetation in arid and semi-arid areas for livestock grazing", "Only cultivated pasture", "Only irrigated land", "Only crop fields"], ans: "Natural vegetation in arid and semi-arid areas for livestock grazing", topic: "Pasture and Range Management" },
    { q: "Improved pastures are established by:", options: ["Sowing selected grasses and legumes", "Only natural regeneration", "Only burning", "Only overgrazing"], ans: "Sowing selected grasses and legumes", topic: "Pasture and Range Management" },
    { q: "Overgrazing leads to:", options: ["Soil erosion, loss of desirable species and desertification", "Only higher productivity", "Only better soil", "Only more forage"], ans: "Soil erosion, loss of desirable species and desertification", topic: "Pasture and Range Management" },
    { q: "Rotational grazing helps to:", options: ["Allow pasture recovery and prevent overgrazing", "Only increase stocking rate", "Only reduce forage", "Only cause erosion"], ans: "Allow pasture recovery and prevent overgrazing", topic: "Pasture and Range Management" },
    { q: "Legumes in pasture are important because they:", options: ["Fix nitrogen and improve soil fertility", "Only provide fibre", "Only increase erosion", "Only reduce quality"], ans: "Fix nitrogen and improve soil fertility", topic: "Pasture and Range Management" },
    { q: "Carrying capacity is:", options: ["The number of animals a pasture can support sustainably", "Only maximum animals", "Only minimum animals", "Only temporary stocking"], ans: "The number of animals a pasture can support sustainably", topic: "Pasture and Range Management" },
    { q: "Pasture establishment requires:", options: ["Good seedbed preparation, correct seeding rate and weed control", "Only broadcasting", "Only burning", "Only overgrazing"], ans: "Good seedbed preparation, correct seeding rate and weed control", topic: "Pasture and Range Management" },
    { q: "Deferred grazing means:", options: ["Resting pasture for a period to allow seed setting and regrowth", "Continuous grazing", "Zero grazing", "Only night grazing"], ans: "Resting pasture for a period to allow seed setting and regrowth", topic: "Pasture and Range Management" },
    { q: "Bush burning in range management can:", options: ["Control woody plants but may damage soil if overdone", "Only improve forage", "Only increase fertility", "Only reduce erosion"], ans: "Control woody plants but may damage soil if overdone", topic: "Pasture and Range Management" },
    { q: "Range improvement practices include:", options: ["Reseeding, fertilization and water point development", "Only overgrazing", "Only burning every year", "Only fencing out"], ans: "Reseeding, fertilization and water point development", topic: "Pasture and Range Management" },
    { q: "Sustainable range management aims at:", options: ["Maintaining productivity while conserving the environment", "Only maximum animals", "Only short-term gain", "Only high stocking"], ans: "Maintaining productivity while conserving the environment", topic: "Pasture and Range Management" },
    { q: "Grazing systems include:", options: ["Continuous, rotational and zero grazing", "Only free range", "Only nomadic", "Only transhumance"], ans: "Continuous, rotational and zero grazing", topic: "Pasture and Range Management" },
    { q: "Pasture and range management is crucial in:", options: ["Livestock production especially in grassland and savanna zones", "Only crop areas", "Only irrigated farms", "Only urban farms"], ans: "Livestock production especially in grassland and savanna zones", topic: "Pasture and Range Management" },
    { q: "Overstocking of rangeland leads to:", options: ["Degradation, loss of biodiversity and reduced productivity", "Only higher income", "Only better animal health", "Only more forage"], ans: "Degradation, loss of biodiversity and reduced productivity", topic: "Pasture and Range Management" },
    { q: "Water points should be properly distributed in range management to:", options: ["Prevent overgrazing around few points", "Only increase cost", "Only reduce animals", "Only cause erosion"], ans: "Prevent overgrazing around few points", topic: "Pasture and Range Management" },
    { q: "Forage conservation methods include:", options: ["Hay making and silage production", "Only fresh feeding", "Only grazing", "Only burning"], ans: "Hay making and silage production", topic: "Pasture and Range Management" },
    { q: "Good pasture management increases:", options: ["Animal performance and reduces supplementary feeding cost", "Only labour", "Only cost", "Only disease"], ans: "Animal performance and reduces supplementary feeding cost", topic: "Pasture and Range Management" },
    { q: "Range management in arid areas requires:", options: ["Careful stocking rates and drought-resistant species", "Only high stocking", "Only exotic breeds", "Only irrigation"], ans: "Careful stocking rates and drought-resistant species", topic: "Pasture and Range Management" },
    { q: "Students learn pasture and range management to:", options: ["Support sustainable livestock production and prevent land degradation", "Only do crop production", "Only nutrition", "Only breeding"], ans: "Support sustainable livestock production and prevent land degradation", topic: "Pasture and Range Management" }
