    { q: "ASME Y14.5 is the American standard for:", options: ["Dimensioning and tolerancing", "Only line types", "Only paper size", "Only title block"], ans: "Dimensioning and tolerancing", topic: "Technical Drawing Standards" },

    { q: "Following standards ensures:", options: ["Drawings are unambiguous and internationally accepted", "Artistic freedom", "Different styles per country", "Confusion in manufacturing"], ans: "Drawings are unambiguous and internationally accepted", topic: "Technical Drawing Standards" },

    { q: "The arrowheads in dimensioning should be:", options: ["Closed and filled or open as per standard", "Only large", "Only small", "Only coloured"], ans: "Closed and filled or open as per standard", topic: "Technical Drawing Standards" },

    { q: "Hatching lines in sectional views should be:", options: ["Uniform, at 45° and spaced properly", "Random", "Only horizontal", "Only vertical"], ans: "Uniform, at 45° and spaced properly", topic: "Technical Drawing Standards" },

    { q: "Technical drawing standards are regularly updated by:", options: ["International organizations like ISO", "Only local governments", "Only schools", "Only companies"], ans: "International organizations like ISO", topic: "Technical Drawing Standards" },

    { q: "The projection symbol tells the reader:", options: ["Which angle projection was used", "Only the scale", "Only the title", "Only the date"], ans: "Which angle projection was used", topic: "Technical Drawing Standards" },

    { q: "Lettering standards specify:", options: ["Height, style and spacing of letters", "Only colour", "Only thickness", "Only direction"], ans: "Height, style and spacing of letters", topic: "Technical Drawing Standards" },

    { q: "Adhering to technical drawing standards reduces:", options: ["Errors and misinterpretation in manufacturing", "Artistic value", "Speed of drawing", "Personal creativity"], ans: "Errors and misinterpretation in manufacturing", topic: "Technical Drawing Standards" },

    { q: "Technical drawing standards are taught so that students can:", options: ["Produce and interpret drawings correctly anywhere in the world", "Only draw artistically", "Only use CAD", "Only sketch"], ans: "Produce and interpret drawings correctly anywhere in the world", topic: "Technical Drawing Standards" },

    { q: "In conclusion, technical drawing standards ensure:", options: ["Global consistency, clarity and professionalism in engineering communication", "Only local understanding", "Only artistic freedom", "Only personal style"], ans: "Global consistency, clarity and professionalism in engineering communication", topic: "Technical Drawing Standards" }

