    // Presentation Skills in French
    { q: "Presentation Skills in French teach students how to:", options: ["Prepare and deliver clear, well-structured oral presentations", "Only speak casually", "Only debate", "Only have conversations"], ans: "Prepare and deliver clear, well-structured oral presentations", topic: "Presentation Skills in French" },
    { q: "A good presentation requires:", options: ["Clear introduction, logical development, visual support and strong conclusion", "Only long speaking time", "Only many slides", "Only perfect grammar"], ans: "Clear introduction, logical development, visual support and strong conclusion", topic: "Presentation Skills in French" },
    { q: "Students learn useful presentation language such as:", options: ["‘Aujourd’hui je vais parler de…’, ‘Tout d’abord…’, ‘Pour conclure…’", "Only greetings", "Only debate phrases", "Only casual conversation"], ans: "‘Aujourd’hui je vais parler de…’, ‘Tout d’abord…’, ‘Pour conclure…’", topic: "Presentation Skills in French" },
    { q: "Preparation for a presentation includes:", options: ["Research, planning, scripting/key points and rehearsal", "Only memorizing a full text", "Only reading notes", "Only speaking without preparation"], ans: "Research, planning, scripting/key points and rehearsal", topic: "Presentation Skills in French" },
    { q: "Visual aids (slides, posters, etc.) should:", options: ["Support the spoken message without overwhelming it", "Only contain all text", "Only be decorative", "Only replace speaking"], ans: "Support the spoken message without overwhelming it", topic: "Presentation Skills in French" },
    { q: "Delivery skills include:", options: ["Clear voice, eye contact, appropriate pace and confident body language", "Only reading from notes", "Only speaking very fast", "Only looking at the floor"], ans: "Clear voice, eye contact, appropriate pace and confident body language", topic: "Presentation Skills in French" },
    { q: "Handling questions after a presentation requires:", options: ["Active listening, clarification and polite response", "Only knowing all answers", "Only avoiding questions", "Only changing topic"], ans: "Active listening, clarification and polite response", topic: "Presentation Skills in French" },
    { q: "Presentation Skills in French help students to:", options: ["Organize ideas and communicate them effectively to an audience", "Only improve pronunciation", "Only increase vocabulary", "Only practice grammar"], ans: "Organize ideas and communicate them effectively to an audience", topic: "Presentation Skills in French" },
    { q: "Students should practice with:", options: ["Timed rehearsals and peer or teacher feedback", "Only silent preparation", "Only writing the script", "Only reading aloud once"], ans: "Timed rehearsals and peer or teacher feedback", topic: "Presentation Skills in French" },
    { q: "Common challenges include:", options: ["Nerves, timing and use of notes", "Only grammar mistakes", "Only vocabulary gaps", "Only pronunciation"], ans: "Nerves, timing and use of notes", topic: "Presentation Skills in French" },
    { q: "Overcoming presentation anxiety involves:", options: ["Preparation, positive visualization and breathing techniques", "Only avoiding presentations", "Only memorizing everything", "Only speaking very fast"], ans: "Preparation, positive visualization and breathing techniques", topic: "Presentation Skills in French" },
    { q: "Effective presentations are:", options: ["Audience-centered, clear and engaging", "Only long", "Only full of data", "Only formal"], ans: "Audience-centered, clear and engaging", topic: "Presentation Skills in French" },
    { q: "Teachers can help by:", options: ["Providing structures, models and constructive feedback", "Only grading strictly", "Only timing", "Only correcting language"], ans: "Providing structures, models and constructive feedback", topic: "Presentation Skills in French" },
    { q: "Presentation skills are valuable for:", options: ["Academic, professional and social contexts", "Only classroom", "Only exams", "Only casual talk"], ans: "Academic, professional and social contexts", topic: "Presentation Skills in French" },
    { q: "Students learn to adapt their presentation according to:", options: ["Audience, purpose and time available", "Only personal preference", "Only length", "Only topic"], ans: "Audience, purpose and time available", topic: "Presentation Skills in French" },
    { q: "Using notes effectively means:", options: ["Having key points rather than reading a full script", "Only reading everything", "Only memorizing", "Only speaking without notes"], ans: "Having key points rather than reading a full script", topic: "Presentation Skills in French" },
    { q: "Presentation Skills in French develop:", options: ["Confidence, clarity and the ability to engage an audience", "Only grammar accuracy", "Only vocabulary", "Only pronunciation"], ans: "Confidence, clarity and the ability to engage an audience", topic: "Presentation Skills in French" },
    { q: "A successful presentation ends with:", options: ["A clear summary and invitation for questions", "Only stopping suddenly", "Only thanking", "Only repeating the introduction"], ans: "A clear summary and invitation for questions", topic: "Presentation Skills in French" },
    { q: "Mastering presentation skills leads to:", options: ["Greater competence and confidence in spoken French communication", "Only fewer mistakes", "Only longer speeches", "Only perfect accent"], ans: "Greater competence and confidence in spoken French communication", topic: "Presentation Skills in French" },
    { q: "In summary, Presentation Skills in French aim to:", options: ["Equip students to deliver effective, engaging and well-organized talks", "Only improve casual conversation", "Only practice grammar", "Only increase vocabulary"], ans: "Equip students to deliver effective, engaging and well-organized talks", topic: "Presentation Skills in French" },

    // Negotiation and Persuasion
    { q: "Negotiation and Persuasion in French involve:", options: ["Convincing others, reaching agreements and handling different viewpoints", "Only casual conversation", "Only presenting facts", "Only debating to win"], ans: "Convincing others, reaching agreements and handling different viewpoints", topic: "Negotiation and Persuasion" },
    { q: "Persuasion techniques include:", options: ["Using logical arguments, emotional appeal and credible evidence", "Only speaking loudly", "Only repeating the same point", "Only avoiding counterarguments"], ans: "Using logical arguments, emotional appeal and credible evidence", topic: "Negotiation and Persuasion" },
    { q: "Negotiation requires:", options: ["Listening, compromising, proposing solutions and finding common ground", "Only insisting on your position", "Only speaking more", "Only using formal language"], ans: "Listening, compromising, proposing solutions and finding common ground", topic: "Negotiation and Persuasion" },
    { q: "Useful language for persuasion includes:", options: ["‘Je vous propose…’, ‘Il serait avantageux de…’, ‘Qu’en pensez-vous ?’", "Only greetings", "Only debate phrases", "Only casual fillers"], ans: "‘Je vous propose…’, ‘Il serait avantageux de…’, ‘Qu’en pensez-vous ?’", topic: "Negotiation and Persuasion" },
    { q: "In negotiation, it is important to:", options: ["Show respect, understand the other party’s needs and seek win-win solutions", "Only defend your position", "Only speak first", "Only reject compromises"], ans: "Show respect, understand the other party’s needs and seek win-win solutions", topic: "Negotiation and Persuasion" },
    { q: "Negotiation and Persuasion skills are useful in:", options: ["Business, academic, social and everyday situations", "Only formal meetings", "Only debates", "Only presentations"], ans: "Business, academic, social and everyday situations", topic: "Negotiation and Persuasion" },
    { q: "Students learn to handle:", options: ["Objections, counteroffers and difficult situations politely", "Only easy agreements", "Only saying no", "Only agreeing always"], ans: "Objections, counteroffers and difficult situations politely", topic: "Negotiation and Persuasion" },
    { q: "A successful negotiator is:", options: ["Flexible, patient, clear and culturally sensitive", "Only aggressive", "Only passive", "Only emotional"], ans: "Flexible, patient, clear and culturally sensitive", topic: "Negotiation and Persuasion" },
    { q: "Persuasion in French often relies on:", options: ["Polite forms, logical structure and appropriate register", "Only emotion", "Only volume", "Only speed"], ans: "Polite forms, logical structure and appropriate register", topic: "Negotiation and Persuasion" },
    { q: "Role-plays of negotiation scenarios help students to:", options: ["Practice real-life language and strategies safely", "Only memorize scripts", "Only improve pronunciation", "Only analyze grammar"], ans: "Practice real-life language and strategies safely", topic: "Negotiation and Persuasion" },
    { q: "Negotiation involves balancing:", options: ["Assertiveness with cooperation", "Only winning", "Only yielding", "Only silence"], ans: "Assertiveness with cooperation", topic: "Negotiation and Persuasion" },
    { q: "Students practice phrases for:", options: ["Making offers, accepting, rejecting and suggesting alternatives", "Only greetings", "Only describing", "Only narrating"], ans: "Making offers, accepting, rejecting and suggesting alternatives", topic: "Negotiation and Persuasion" },
    { q: "Cultural awareness is important in negotiation because:", options: ["Different cultures have different styles and expectations", "Only language matters", "Only grammar matters", "Only vocabulary matters"], ans: "Different cultures have different styles and expectations", topic: "Negotiation and Persuasion" },
    { q: "Effective persuasion avoids:", options: ["Aggression and instead uses reasoned and respectful arguments", "Only polite language", "Only logical points", "Only evidence"], ans: "Aggression and instead uses reasoned and respectful arguments", topic: "Negotiation and Persuasion" },
    { q: "Negotiation and Persuasion develop:", options: ["Advanced interactive, strategic and diplomatic language use", "Only basic conversation", "Only presentations", "Only debates"], ans: "Advanced interactive, strategic and diplomatic language use", topic: "Negotiation and Persuasion" },
    { q: "A good negotiator knows when to:", options: ["Compromise and when to stand firm", "Only insist", "Only yield", "Only speak"], ans: "Compromise and when to stand firm", topic: "Negotiation and Persuasion" },
    { q: "Post-negotiation reflection helps students to:", options: ["Learn from the experience and improve future performance", "Only celebrate winning", "Only forget the outcome", "Only repeat the same strategy"], ans: "Learn from the experience and improve future performance", topic: "Negotiation and Persuasion" },
    { q: "The course encourages:", options: ["Ethical and constructive approaches to persuasion and negotiation", "Only winning at all costs", "Only avoiding conflict", "Only formal language"], ans: "Ethical and constructive approaches to persuasion and negotiation", topic: "Negotiation and Persuasion" },
    { q: "Mastering Negotiation and Persuasion leads to:", options: ["Stronger ability to influence and collaborate effectively in French", "Only more vocabulary", "Only better grammar", "Only perfect pronunciation"], ans: "Stronger ability to influence and collaborate effectively in French", topic: "Negotiation and Persuasion" },
    { q: "In summary, Negotiation and Persuasion focus on:", options: ["Strategic, respectful and effective spoken interaction for achieving goals", "Only casual talk", "Only presentations", "Only basic conversation"], ans: "Strategic, respectful and effective spoken interaction for achieving goals", topic: "Negotiation and Persuasion" }
