    { q: "Stylistic analysis pays attention to:", options: ["Language use, literary devices and narrative techniques", "Only grammar", "Only vocabulary", "Only spelling"], ans: "Language use, literary devices and narrative techniques", topic: "Literary Analysis of African Texts" },
    { q: "Thematic analysis explores:", options: ["How major themes are developed and their significance", "Only the story line", "Only characters", "Only setting"], ans: "How major themes are developed and their significance", topic: "Literary Analysis of African Texts" },
    { q: "When analyzing oral-influenced texts, consider:", options: ["Rhythm, repetition, performance elements and cultural context", "Only written style", "Only European forms", "Only modern techniques"], ans: "Rhythm, repetition, performance elements and cultural context", topic: "Literary Analysis of African Texts" },
    { q: "Literary analysis of African texts should avoid:", options: ["Eurocentric frameworks and oversimplification", "Only using evidence", "Only close reading", "Only contextual awareness"], ans: "Eurocentric frameworks and oversimplification", topic: "Literary Analysis of African Texts" },
    { q: "Effective analysis demonstrates:", options: ["Sensitivity to cultural nuances and depth of understanding", "Only correct grammar", "Only long essays", "Only personal views"], ans: "Sensitivity to cultural nuances and depth of understanding", topic: "Literary Analysis of African Texts" },
    { q: "Students can improve analysis by:", options: ["Practicing on diverse texts and engaging in discussion", "Only reading summaries", "Only memorizing", "Only translating"], ans: "Practicing on diverse texts and engaging in discussion", topic: "Literary Analysis of African Texts" },
    { q: "A complete literary analysis usually includes:", options: ["Introduction, detailed examination and insightful conclusion", "Only summary", "Only opinion", "Only facts"], ans: "Introduction, detailed examination and insightful conclusion", topic: "Literary Analysis of African Texts" },
    { q: "Literary analysis of African texts helps students to:", options: ["Appreciate the richness, diversity and power of African writing", "Only pass exams", "Only enjoy stories", "Only learn history"], ans: "Appreciate the richness, diversity and power of African writing", topic: "Literary Analysis of African Texts" },
    { q: "Context is crucial because:", options: ["It shapes the meaning and significance of the text", "Only the text matters", "Only personal response", "Only plot"], ans: "It shapes the meaning and significance of the text", topic: "Literary Analysis of African Texts" },
    { q: "Analysis should be supported by:", options: ["Specific references and quotations from the text", "Only general statements", "Only personal experience", "Only imagination"], ans: "Specific references and quotations from the text", topic: "Literary Analysis of African Texts" },
    { q: "Different critical approaches can lead to:", options: ["Multiple valid readings of the same text", "Only one correct interpretation", "Only teacher’s view", "Only popular opinion"], ans: "Multiple valid readings of the same text", topic: "Literary Analysis of African Texts" },
    { q: "Literary analysis develops the ability to:", options: ["Think critically and articulate nuanced interpretations", "Only summarize", "Only translate", "Only enjoy reading"], ans: "Think critically and articulate nuanced interpretations", topic: "Literary Analysis of African Texts" },
    { q: "In Francophone African literature, analysis often reveals:", options: ["Complex negotiations between tradition, modernity, colonialism and independence", "Only simple stories", "Only European influence", "Only oral roots"], ans: "Complex negotiations between tradition, modernity, colonialism and independence", topic: "Literary Analysis of African Texts" },
    { q: "Mastering literary analysis equips students to:", options: ["Engage deeply with African and world literature", "Only speak better", "Only write summaries", "Only pass exams"], ans: "Engage deeply with African and world literature", topic: "Literary Analysis of African Texts" },
    { q: "In summary, literary analysis of African texts is:", options: ["A critical skill for uncovering the depth, beauty and significance of African writing", "Only summary writing", "Only personal response", "Only for advanced students"], ans: "A critical skill for uncovering the depth, beauty and significance of African writing", topic: "Literary Analysis of African Texts" }
