    { q: "Creative writing tasks should be:", options: ["Enjoyable, challenging and open to personal expression", "Only strict", "Only rule-based", "Only for marks"], ans: "Enjoyable, challenging and open to personal expression", topic: "Creative Writing in French" },
    { q: "Feedback on creative writing should focus on:", options: ["Creativity, originality and effectiveness of expression", "Only grammar errors", "Only spelling", "Only length"], ans: "Creativity, originality and effectiveness of expression", topic: "Creative Writing in French" },
    { q: "Creative writing encourages risk-taking by:", options: ["Allowing experimentation with language and ideas", "Only following models", "Only copying", "Only using simple sentences"], ans: "Allowing experimentation with language and ideas", topic: "Creative Writing in French" },
    { q: "A creative writing piece should have:", options: ["Engaging content, clear structure and appropriate style", "Only correct grammar", "Only long length", "Only difficult words"], ans: "Engaging content, clear structure and appropriate style", topic: "Creative Writing in French" },
    { q: "Creative writing complements:", options: ["Other language skills and fosters deeper engagement with French", "Only grammar study", "Only listening", "Only reading"], ans: "Other language skills and fosters deeper engagement with French", topic: "Creative Writing in French" },
    { q: "Students can improve creative writing through:", options: ["Regular practice, reading models and experimenting with techniques", "Only memorizing rules", "Only writing exams", "Only copying texts"], ans: "Regular practice, reading models and experimenting with techniques", topic: "Creative Writing in French" },
    { q: "The process of creative writing usually involves:", options: ["Idea generation, drafting, revising and polishing", "Only one draft", "Only final copy", "Only teacher correction"], ans: "Idea generation, drafting, revising and polishing", topic: "Creative Writing in French" },
    { q: "Creative writing tasks can be inspired by:", options: ["Pictures, music, experiences and prompts", "Only grammar topics", "Only vocabulary lists", "Only exams"], ans: "Pictures, music, experiences and prompts", topic: "Creative Writing in French" },
    { q: "Good creative writing shows:", options: ["Imagination, originality and effective use of language", "Only perfect grammar", "Only long sentences", "Only difficult vocabulary"], ans: "Imagination, originality and effective use of language", topic: "Creative Writing in French" },
    { q: "Creative writing helps students to:", options: ["Develop a personal voice and deeper appreciation of French", "Only pass exams", "Only speak better", "Only listen well"], ans: "Develop a personal voice and deeper appreciation of French", topic: "Creative Writing in French" },
    { q: "Teachers can support creative writing by:", options: ["Providing stimulating prompts and constructive feedback", "Only giving marks", "Only correcting errors", "Only lecturing"], ans: "Providing stimulating prompts and constructive feedback", topic: "Creative Writing in French" },
    { q: "In summary, creative writing in French is designed to:", options: ["Foster imagination, self-expression and advanced language use", "Only teach grammar", "Only improve writing for exams", "Only prepare for formal tasks"], ans: "Foster imagination, self-expression and advanced language use", topic: "Creative Writing in French" },

    // Letter Writing
    { q: "Letter writing in French includes:", options: ["Formal and informal letters for different purposes", "Only emails", "Only text messages", "Only reports"], ans: "Formal and informal letters for different purposes", topic: "Letter Writing" },
    { q: "A formal letter in French typically includes:", options: ["Sender’s address, date, recipient’s address, salutation, body, closing and signature", "Only body", "Only salutation", "Only signature"], ans: "Sender’s address, date, recipient’s address, salutation, body, closing and signature", topic: "Letter Writing" },
    { q: "The salutation in a formal French letter is:", options: ["'Monsieur', 'Madame' or 'Chère Madame' etc.", "Only 'Salut'", "Only 'Coucou'", "Only 'Bonjour'"], ans: "'Monsieur', 'Madame' or 'Chère Madame' etc.", topic: "Letter Writing" },
    { q: "The body of a formal letter should be:", options: ["Clear, polite and well-organized", "Only casual", "Only short", "Only emotional"], ans: "Clear, polite and well-organized", topic: "Letter Writing" },
    { q: "Common formal letter types include:", options: ["Letters of application, complaint, request and invitation", "Only love letters", "Only chat messages", "Only diaries"], ans: "Letters of application, complaint, request and invitation", topic: "Letter Writing" },
    { q: "In informal letters to friends, students can use:", options: ["Friendly tone, contractions and colloquial expressions", "Only formal language", "Only passive voice", "Only complex sentences"], ans: "Friendly tone, contractions and colloquial expressions", topic: "Letter Writing" },
    { q: "The closing of an informal French letter often uses:", options: ["'Bisous', 'Amitiés' or 'À bientôt'", "Only formal closings", "Only 'Veuillez agréer'", "Only 'Cordialement'"], ans: "'Bisous', 'Amitiés' or 'À bientôt'", topic: "Letter Writing" },
    { q: "Letter writing teaches students to:", options: ["Adapt language according to audience and purpose", "Only speak", "Only listen", "Only read"], ans: "Adapt language according to audience and purpose", topic: "Letter Writing" },
    { q: "A letter of complaint should:", options: ["State the problem clearly, provide details and suggest a solution politely", "Only be angry", "Only be short", "Only demand money"], ans: "State the problem clearly, provide details and suggest a solution politely", topic: "Letter Writing" },
    { q: "The date in a French letter is usually written as:", options: ["'Le 15 avril 2026' or similar formal style", "Only numbers", "Only month first", "Only year only"], ans: "'Le 15 avril 2026' or similar formal style", topic: "Letter Writing" },
    { q: "Letter writing practice improves:", options: ["Organization, politeness and appropriate register", "Only speed", "Only length", "Only handwriting"], ans: "Organization, politeness and appropriate register", topic: "Letter Writing" },
    { q: "Students should learn the difference between:", options: ["Formal and informal letter formats and language", "Only one style", "Only business letters", "Only personal letters"], ans: "Formal and informal letter formats and language", topic: "Letter Writing" },
    { q: "A letter of application usually includes:", options: ["Introduction, qualifications, experience and polite closing", "Only demands", "Only complaints", "Only thanks"], ans: "Introduction, qualifications, experience and polite closing", topic: "Letter Writing" },
    { q: "Proper structure in letter writing helps to:", options: ["Make the message clear and professional", "Only increase length", "Only add difficulty", "Only confuse the reader"], ans: "Make the message clear and professional", topic: "Letter Writing" },
    { q: "Letter writing is a practical skill because it is used in:", options: ["Everyday communication, academics and professional life", "Only chatting", "Only social media", "Only diaries"], ans: "Everyday communication, academics and professional life", topic: "Letter Writing" },
    { q: "Teachers can improve letter writing by:", options: ["Providing models, guided practice and feedback on register", "Only giving marks", "Only correcting errors", "Only lecturing"], ans: "Providing models, guided practice and feedback on register", topic: "Letter Writing" },
    { q: "Mastering letter writing enables students to:", options: ["Communicate effectively and appropriately in written French", "Only speak better", "Only listen well", "Only read fast"], ans: "Communicate effectively and appropriately in written French", topic: "Letter Writing" },
    { q: "Common elements in both formal and informal letters are:", options: ["Clear purpose, polite tone and proper structure", "Only length", "Only vocabulary", "Only grammar"], ans: "Clear purpose, polite tone and proper structure", topic: "Letter Writing" },
    { q: "Letter writing practice should be:", options: ["Regular and linked to real-life situations", "Only once", "Only for exams", "Only theoretical"], ans: "Regular and linked to real-life situations", topic: "Letter Writing" },
    { q: "In summary, letter writing in French is:", options: ["An essential skill for clear, appropriate and effective written communication", "Only formal", "Only informal", "Only for business"], ans: "An essential skill for clear, appropriate and effective written communication", topic: "Letter Writing" },

    // Descriptive and Narrative Writing
    { q: "Descriptive writing aims to:", options: ["Create a vivid picture using sensory details and precise language", "Only tell a story", "Only argue a point", "Only explain facts"], ans: "Create a vivid picture using sensory details and precise language", topic: "Descriptive and Narrative Writing" },
    { q: "Narrative writing focuses on:", options: ["Telling a story with characters, setting, plot and resolution", "Only describing places", "Only giving opinions", "Only listing events"], ans: "Telling a story with characters, setting, plot and resolution", topic: "Descriptive and Narrative Writing" },
    { q: "Good descriptive writing uses:", options: ["Adjectives, adverbs and figurative language", "Only simple sentences", "Only facts", "Only opinions"], ans: "Adjectives, adverbs and figurative language", topic: "Descriptive and Narrative Writing" },
    { q: "In narrative writing, the plot should have:", options: ["Beginning, middle and end with conflict and resolution", "Only description", "Only dialogue", "Only conclusion"], ans: "Beginning, middle and end with conflict and resolution", topic: "Descriptive and Narrative Writing" },
    { q: "Descriptive and narrative writing can be combined when:", options: ["Telling a story while vividly describing scenes and characters", "Only describing", "Only narrating", "Only arguing"], ans: "Telling a story while vividly describing scenes and characters", topic: "Descriptive and Narrative Writing" },
    { q: "Sensory details in descriptive writing appeal to:", options: ["Sight, sound, smell, taste and touch", "Only sight", "Only sound", "Only touch"], ans: "Sight, sound, smell, taste and touch", topic: "Descriptive and Narrative Writing" },
    { q: "Character development in narrative writing involves:", options: ["Showing personality through actions, dialogue and thoughts", "Only naming characters", "Only describing appearance", "Only listing events"], ans: "Showing personality through actions, dialogue and thoughts", topic: "Descriptive and Narrative Writing" },
    { q: "A strong narrative hook can be:", options: ["An interesting beginning that captures the reader’s attention", "Only a long introduction", "Only a summary", "Only a conclusion"], ans: "An interesting beginning that captures the reader’s attention", topic: "Descriptive and Narrative Writing" },
    { q: "Descriptive and narrative writing help students to:", options: ["Develop creativity, vocabulary and expressive ability", "Only follow rules", "Only write reports", "Only prepare for exams"], ans: "Develop creativity, vocabulary and expressive ability", topic: "Descriptive and Narrative Writing" },
    { q: "In descriptive writing, spatial organization means:", options: ["Describing from one point to another in an orderly way", "Only listing items", "Only giving opinions", "Only telling time"], ans: "Describing from one point to another in an orderly way", topic: "Descriptive and Narrative Writing" },
    { q: "Dialogue in narrative writing helps to:", options: ["Reveal character and advance the plot", "Only describe scenes", "Only give background", "Only conclude"], ans: "Reveal character and advance the plot", topic: "Descriptive and Narrative Writing" },
    { q: "Effective descriptive writing avoids:", options: ["Clichés and vague language", "Only simple words", "Only short sentences", "Only facts"], ans: "Clichés and vague language", topic: "Descriptive and Narrative Writing" },
    { q: "Narrative writing should maintain:", options: ["Consistent tense and clear point of view", "Only many flashbacks", "Only long descriptions", "Only dialogue"], ans: "Consistent tense and clear point of view", topic: "Descriptive and Narrative Writing" },
    { q: "Descriptive and narrative pieces should be:", options: ["Engaging, well-structured and rich in detail", "Only long", "Only difficult", "Only formal"], ans: "Engaging, well-structured and rich in detail", topic: "Descriptive and Narrative Writing" },
    { q: "Students can improve these skills by:", options: ["Reading good models and practicing regularly", "Only memorizing rules", "Only writing exams", "Only copying"], ans: "Reading good models and practicing regularly", topic: "Descriptive and Narrative Writing" },
    { q: "The combination of description and narration creates:", options: ["Rich, immersive stories and scenes", "Only dry reports", "Only arguments", "Only explanations"], ans: "Rich, immersive stories and scenes", topic: "Descriptive and Narrative Writing" },
    { q: "Teachers can support students by:", options: ["Giving creative prompts and constructive feedback", "Only giving marks", "Only correcting errors", "Only lecturing"], ans: "Giving creative prompts and constructive feedback", topic: "Descriptive and Narrative Writing" },
    { q: "Descriptive and narrative writing foster:", options: ["Creativity, observation skills and emotional expression", "Only grammar accuracy", "Only exam preparation", "Only formal style"], ans: "Creativity, observation skills and emotional expression", topic: "Descriptive and Narrative Writing" },
    { q: "Mastering descriptive and narrative writing enables students to:", options: ["Tell engaging stories and paint vivid pictures in French", "Only write formal letters", "Only do business writing", "Only prepare reports"], ans: "Tell engaging stories and paint vivid pictures in French", topic: "Descriptive and Narrative Writing" },
    { q: "In summary, descriptive and narrative writing are:", options: ["Powerful tools for creative expression and effective communication in French", "Only for exams", "Only formal", "Only technical"], ans: "Powerful tools for creative expression and effective communication in French", topic: "Descriptive and Narrative Writing" }
